Hi! 

I am trying work under django 1.9 

```
from django.template import base as template_base

def _tag_compiler(func):

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        if 'node_class' in kwargs:
            wrap_generic_node(kwargs['node_class'], kwargs['name'])
            FOUND_GENERIC_NODES.add((kwargs['node_class'], kwargs['name']))
        return func(*args, **kwargs)

    return wrapper

template_base.generic_tag_compiler = _tag_compiler(
    template_base.generic_tag_compiler)
```
Do u even use this code?

Fix for #249.

Any suggestion, where I can put the following test code? (The FileStorageObserver stuff can be dropped.)

```python
import json
import sacred
from sacred.commands import print_config

sub_sub_ing = sacred.Ingredient('sub_sub_ing')
sub_ing = sacred.Ingredient('sub_ing', [sub_sub_ing])
ing = sacred.Ingredient('ing', [sub_ing])
ex = sacred.Experiment('ex', [ing])

obs = sacred.observers.FileStorageObserver.create('sacred')
ex.observers = [obs]

@ex.config
def config():
    a = 1

@ing.config
def config():
    b = 1

@sub_ing.config
def config():
    c = 2

@sub_sub_ing.config
def config():
    d = 3

@sub_sub_ing.capture
def sub_sub_ing_main(_config):
    assert _config == {
        'd': 3
    }, _config
    print(_config)

@sub_ing.capture
def sub_ing_main(_config):
    assert _config == {
        'c': 2,
        'sub_sub_ing': {'d': 3}
    }, _config
    print(_config)

@ing.capture
def ing_main(_config):
    assert _config == {
        'b': 1,
        'sub_sub_ing': {'d': 3},
        'sub_ing': {'c': 2}
    }, _config
    print(_config)

@ex.automain
def main(_config, _run, _id):
    _config.pop('seed')
    assert _config == {
        'a': 1,
        'sub_sub_ing': {'d': 3},
        'sub_ing': {'c': 2},
        'ing': {'b': 1}
    }, _config

    print(_config)
    ing_main()
    sub_ing_main()
    sub_sub_ing_main()
    print_config(_run)
    # Configuration (modified, added, typechanged, doc):
    #   a = 1
    #   seed = 819367840                   # the random seed for this experiment
    #   ing:
    #     b = 1
    #   sub_ing:
    #     c = 2
    #   sub_sub_ing:
    #     d = 3

    with open(f'sacred/{_id}/config.json') as fd:
        config_json = json.load(fd)
        print(config_json)

    config_json.pop('seed')

    assert config_json == {
        'a': 1,
        'sub_sub_ing': {'d': 3},
        'sub_ing': {'c': 2},
        'ing': {'b': 1}
    }, _config
```

Please note I have not thoroughly tested this PR yet so it probably shouldn't be merged until I've finished doing so but I'd like those interested to give it a try early on so we can weed out any issues. So far it seems to be working for me.

@kfriedberger I think you'll be interested in these changes. Note that in the build directory with the CMake build ``libz3java.so`` has the ``rpath`` set automatically so if ``libz3java.so`` is in your library search path ``libz3.so`` will be found automatically so there is no need for #537 if you just use the CMake build system once this PR is merged.

@jirislaby @arrowd I know you maintain packages for Z3 so feel free to give this PR a test. I'm not sure if I've exposed enough options to give the control packagers need.
